from dataclasses import dataclass

@dataclass
class Item:
    """Represents an item in an order."""
    name: str
    price: float

"""Custom exceptions for the application"""

class InvalidItemError(Exception):
    """Base class for exceptions raised when an item is invalid."""
    pass

class MissingItemFieldError(InvalidItemError):
    """Raised when a required field is missing from an item."""
    pass

class InvalidItemPriceError(InvalidItemError):
    """Raised when an item has an invalid price."""
    pass

import unittest
from src.order_processing import calculate_total, process_order, validate_item_data
from src.models import Item
from src.custom_exceptions import MissingItemFieldError, InvalidItemPriceError

class TestOrderProcessing(unittest.TestCase):

    def test_calculate_total_success(self):
        """Test that calculate_total returns the correct total."""
        items = [Item('Item 1', 10.0), Item('Item 2', 20.0)]
        self.assertEqual(calculate_total(items), 30.0)

    def test_calculate_total_empty_list(self):
        """Test that calculate_total returns 0 for an empty list."""
        self.assertEqual(calculate_total([]), 0.0)

    def test_process_order_success(self):
        """Test that process_order returns the correct response."""
        items_data = [{'name': 'Item 1', 'price': 10.0}]
        expected_response = {'order_id': 'ORD-001', 'total': 10.0, 'status': 'processed'}
        self.assertEqual(process_order('ORD-001', items_data), expected_response)

    def test_process_order_invalid_item_data(self):
        """Test that process_order raises an exception for invalid item data."""
        with self.assertRaises(MissingItemFieldError):
            process_order('ORD-001', [{'name': 'Item 1'}])

    def test_validate_item_data_success(self):
        """Test that validate_item_data passes for valid data."""
        try:
            validate_item_data({'name': 'Item 1', 'price': 10.0})
        except (MissingItemFieldError, InvalidItemPriceError):
            self.fail("validate_item_data() raised an exception unexpectedly!")

    def test_validate_item_data_missing_field(self):
        """Test that validate_item_data raises MissingItemFieldError."""
        with self.assertRaises(MissingItemFieldError):
            validate_item_data({'name': 'Item 1'})

    def test_validate_item_data_invalid_price(self):
        """Test that validate_item_data raises InvalidItemPriceError."""
        with self.assertRaises(InvalidItemPriceError):
            validate_item_data({'name': 'Item 1', 'price': -10.0})

if __name__ == '__main__':
    unittest.main()

