if __name__ == '__main__':
    # Example with valid items
    valid_items = [
        {'name': 'Item 1', 'price': 10.0},
        {'name': 'Item 2', 'price': 20.0}
    ]
    try:
        result = process_order('ORD-001', valid_items)
